using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace McpServer;

// The [McpServerToolType] attribute marks this class for discovery by WithToolsFromAssembly().
// The SDK creates one instance per tool invocation, resolving constructor args from DI.
[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _http;

    // HttpClient is injected by IHttpClientFactory because we registered
    // AddHttpClient<WeatherTools>() in Program.cs.
    public WeatherTools(HttpClient http)
    {
        _http = http;
    }

    // Each [McpServerTool] method becomes a callable tool.
    // [Description] is sent to the LLM so it knows when/how to use the tool.
    // Parameters with [Description] give the LLM argument-level guidance.
    [McpServerTool, Description("Get current weather for a location.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude, e.g. 47.6")] double latitude,
        [Description("Longitude, e.g. -122.3")] double longitude)
    {
        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        using var response = await _http.GetAsync(url);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>();
        var current = json.GetProperty("current");

        var temp = current.GetProperty("temperature_2m").GetDouble();
        var wind = current.GetProperty("wind_speed_10m").GetDouble();

        return $"Temperature: {temp}°C, Wind: {wind} km/h";
    }

    [McpServerTool, Description("Look up coordinates for a city name.")]
    public async Task<string> GeocodeCityName(
        [Description("City name, e.g. Seattle")] string city)
    {
        var url = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(city)}&count=1";
        using var response = await _http.GetAsync(url);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>();

        if (!json.TryGetProperty("results", out var results) || results.GetArrayLength() == 0)
            return $"No results found for '{city}'.";

        var first = results[0];
        var name = first.GetProperty("name").GetString();
        var lat = first.GetProperty("latitude").GetDouble();
        var lon = first.GetProperty("longitude").GetDouble();

        return $"{name}: {lat}, {lon}";
    }
}

